from typing import List

class BookMyShow:

    def __init__(self, n: int, m: int):
        self.n = n
        self.m = m
        self.rows = [[0]*m for _ in range(n)]

    def gather(self, k: int, maxRow: int) -> List[int]:
        for r in range(min(maxRow+1, self.n)):
            if sum(self.rows[r]) + k <= self.m:
                return [r, sum(self.rows[r]) % self.m]
        return []

    def scatter(self, k: int, maxRow: int) -> bool:
        for r in range(min(maxRow+1, self.n)):
            for c in range(self.m):
                if sum(self.rows[r]) < self.m and (sum(self.rows[r]) + k <= self.m):
                    self.rows[r][c % self.m] = 1
                    if c + k <= self.m:
                        for i in range(1, k):
                            self.rows[r][(c + i) % self.m] = 1
